import { BreakpointObserver } from '@angular/cdk/layout';
import { Injectable, Signal, inject } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';

export const BREAKPOINTS = {
  xs: '(min-width: 480px)',
  sm: '(min-width: 640px)',
  md: '(min-width: 768px)',
  lg: '(min-width: 1024px)',
  xl: '(min-width: 1280px)',
  '2xl': '(min-width: 1920px)',
} as const;

export type Breakpoint = keyof typeof BREAKPOINTS;

@Injectable({ providedIn: 'root' })
export class BreakpointService {
  private readonly observer = inject(BreakpointObserver);

  matches(bp: Breakpoint): Signal<boolean> {
    return toSignal(
      this.observer.observe(BREAKPOINTS[bp]).pipe(map((state) => state.matches)),
      { initialValue: this.observer.isMatched(BREAKPOINTS[bp]) },
    );
  }

  isMatched(bp: Breakpoint): boolean {
    return this.observer.isMatched(BREAKPOINTS[bp]);
  }
}

import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { TmdbConfigService } from '../tmdb/tmdb-config.service';
import { TmdbClient } from '../tmdb/tmdb.client';
import { TmdbCastMember, TmdbCrewMember, TmdbTvCreator, TmdbVideo, TmdbWatchProvider } from '../tmdb/tmdb.models';
import { CastMember, CrewMember, MediaDetail, WatchProviderItem, WatchProviders } from './detail.models';

const CAST_LIMIT = 10;
const LANG_PRIORITY: Record<string, number> = { it: 0, en: 1 };

export function pickTrailer(videos: TmdbVideo[]): string | null {
  const candidates = videos.filter((v) => v.site === 'YouTube' && v.type === 'Trailer');
  if (candidates.length === 0) return null;
  const sorted = [...candidates].sort((a, b) => {
    if (a.official !== b.official) return a.official ? -1 : 1;
    const pa = LANG_PRIORITY[a.iso_639_1] ?? 2;
    const pb = LANG_PRIORITY[b.iso_639_1] ?? 2;
    return pa - pb;
  });
  return sorted[0].key;
}

function toWatchProviderItem(p: TmdbWatchProvider): WatchProviderItem {
  return { id: p.provider_id, name: p.provider_name, logoPath: p.logo_path };
}

function toCastMember(c: TmdbCastMember): CastMember {
  return { id: c.id, name: c.name, character: c.character, profilePath: c.profile_path };
}

function toCrewMemberFromCrew(c: TmdbCrewMember): CrewMember {
  return { id: c.id, name: c.name, job: c.job, profilePath: c.profile_path };
}

function toCrewMemberFromCreator(c: TmdbTvCreator): CrewMember {
  return { id: c.id, name: c.name, job: 'Creator', profilePath: c.profile_path };
}

function toWatchProviders(region: { link?: string; flatrate?: TmdbWatchProvider[]; rent?: TmdbWatchProvider[]; buy?: TmdbWatchProvider[] }): WatchProviders {
  return {
    link: region.link,
    flatrate: (region.flatrate ?? []).map(toWatchProviderItem),
    rent: (region.rent ?? []).map(toWatchProviderItem),
    buy: (region.buy ?? []).map(toWatchProviderItem),
  };
}

@Injectable({ providedIn: 'root' })
export class DetailService {
  private readonly tmdb = inject(TmdbClient);
  private readonly config = inject(TmdbConfigService);

  getMovieDetail(id: number): Observable<MediaDetail> {
    return this.tmdb.getMovieDetail(id).pipe(
      map((detail) => {
        const regionProviders = detail['watch/providers']?.results[this.config.region] ?? null;
        return {
          id: detail.id,
          title: detail.title,
          mediaType: 'movie' as const,
          posterPath: detail.poster_path,
          backdropPath: detail.backdrop_path,
          overview: detail.overview,
          voteAverage: detail.vote_average,
          releaseDate: detail.release_date,
          runtime: detail.runtime,
          genres: detail.genres,
          cast: (detail.credits?.cast ?? []).slice(0, CAST_LIMIT).map(toCastMember),
          crew: (detail.credits?.crew ?? []).filter((c) => c.job === 'Director').map(toCrewMemberFromCrew),
          trailerKey: pickTrailer(detail.videos?.results ?? []),
          watchProviders: regionProviders ? toWatchProviders(regionProviders) : null,
        };
      }),
    );
  }

  getTvDetail(id: number): Observable<MediaDetail> {
    return this.tmdb.getTvDetail(id).pipe(
      map((detail) => {
        const regionProviders = detail['watch/providers']?.results[this.config.region] ?? null;
        const runtime = detail.episode_run_time[0] ?? null;
        return {
          id: detail.id,
          title: detail.name,
          mediaType: 'tv' as const,
          posterPath: detail.poster_path,
          backdropPath: detail.backdrop_path,
          overview: detail.overview,
          voteAverage: detail.vote_average,
          releaseDate: detail.first_air_date,
          runtime,
          genres: detail.genres,
          cast: (detail.credits?.cast ?? []).slice(0, CAST_LIMIT).map(toCastMember),
          crew: (detail.created_by ?? []).map(toCrewMemberFromCreator),
          trailerKey: pickTrailer(detail.videos?.results ?? []),
          watchProviders: regionProviders ? toWatchProviders(regionProviders) : null,
        };
      }),
    );
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { Subscription } from 'rxjs';
import { map } from 'rxjs/operators';
import { TmdbClient } from '../tmdb/tmdb.client';
import { TmdbMovie, TmdbTvShow } from '../tmdb/tmdb.models';
import { pickRandom } from './random-picker';
import { PickedItem, SelectionCriteria, SelectionState } from './selection.models';
import { SeenTitlesService } from './seen-titles.service';

function toPickedItem(item: TmdbMovie | TmdbTvShow, mediaType: 'movie' | 'tv'): PickedItem {
  if (mediaType === 'movie') {
    const m = item as TmdbMovie;
    return {
      id: m.id,
      title: m.title,
      mediaType,
      posterPath: m.poster_path,
      overview: m.overview,
      voteAverage: m.vote_average,
      releaseDate: m.release_date,
    };
  }
  const t = item as TmdbTvShow;
  return {
    id: t.id,
    title: t.name,
    mediaType,
    posterPath: t.poster_path,
    overview: t.overview,
    voteAverage: t.vote_average,
    releaseDate: t.first_air_date,
  };
}

@Injectable({ providedIn: 'root' })
export class DiscoverSelectionService {
  private readonly tmdb = inject(TmdbClient);
  private readonly seen = inject(SeenTitlesService);

  readonly state = signal<SelectionState>({ status: 'idle' });

  private _currentCriteria: SelectionCriteria | null = null;
  private _currentPool: PickedItem[] = [];
  private _currentPage = 1;
  private _sub: Subscription | null = null;

  pick(criteria: SelectionCriteria): void {
    this._currentCriteria = criteria;
    this._currentPool = [];
    this._currentPage = 1;
    this._fetchPage();
  }

  pickAnother(): void {
    if (!this._currentCriteria) return;
    this._tryPickFromPool();
  }

  reset(): void {
    this._sub?.unsubscribe();
    this._currentCriteria = null;
    this._currentPool = [];
    this._currentPage = 1;
    this.state.set({ status: 'idle' });
  }

  private _fetchPage(): void {
    this.state.set({ status: 'loading' });

    const { mediaType, genreIds, providerIds, minRating, watchRegion, query } = this._currentCriteria!;

    const request$ = query
      ? this.tmdb.search({ mediaType, query, page: this._currentPage })
      : this.tmdb.discover({
          mediaType,
          page: this._currentPage,
          withGenres: genreIds,
          withWatchProviders: providerIds,
          voteAverageGte: minRating,
          watchRegion,
        });

    this._sub?.unsubscribe();
    this._sub = request$
      .pipe(map((response) => response.results.map((item) => toPickedItem(item as TmdbMovie | TmdbTvShow, mediaType))))
      .subscribe({
        next: (items) => {
          if (items.length === 0 && this._currentPage === 1) {
            this.state.set({ status: 'empty' });
            return;
          }
          if (items.length === 0) {
            this.state.set({ status: 'exhausted' });
            return;
          }
          this._currentPool = items;
          this._tryPickFromPool();
        },
        error: (err: Error) => {
          this.state.set({ status: 'error', message: err.message });
        },
      });
  }

  private _tryPickFromPool(): void {
    const unseen = this._currentPool.filter((item) => !this.seen.has(item.id));

    if (unseen.length > 0) {
      const picked = pickRandom(unseen);
      this.seen.markSeen(picked.id);
      this.state.set({ status: 'picked', item: picked });
      return;
    }

    if (this._currentPool.length === 0) {
      this.state.set({ status: 'empty' });
      return;
    }

    // All items in current page are seen; advance to next page
    this._currentPage += 1;
    this._fetchPage();
  }
}

import { Injectable, NgZone, OnDestroy, inject } from '@angular/core';
import { Subject } from 'rxjs';
import { InputAction, NormalizedInputEvent } from './input-event.model';

const KEY_ACTION_MAP: Record<string, InputAction> = {
  ArrowUp: 'navigate-up',
  ArrowDown: 'navigate-down',
  ArrowLeft: 'navigate-left',
  ArrowRight: 'navigate-right',
  Enter: 'confirm',
  ' ': 'confirm',
  Escape: 'back',
  Backspace: 'back',
};

@Injectable({ providedIn: 'root' })
export class InputDispatcherService implements OnDestroy {
  private readonly zone = inject(NgZone);
  private readonly _events$ = new Subject<NormalizedInputEvent>();

  readonly events$ = this._events$.asObservable();

  private readonly _keyHandler = (event: KeyboardEvent): void => {
    const action = KEY_ACTION_MAP[event.key];
    if (action) {
      this.zone.run(() => {
        this._events$.next({ action, originalEvent: event });
      });
    }
  };

  constructor() {
    this.zone.runOutsideAngular(() => {
      window.addEventListener('keydown', this._keyHandler);
    });
  }

  ngOnDestroy(): void {
    window.removeEventListener('keydown', this._keyHandler);
    this._events$.complete();
  }

  dispatch(action: InputAction, originalEvent: Event): void {
    this._events$.next({ action, originalEvent });
  }
}

