import { Injectable } from '@angular/core';
import { ProviderLaunchPayload } from '../platform/platform.model';

interface ProviderConfig {
  /** Search-prefilled or direct URL builder for this provider */
  buildUrl: (title: string) => string;
  /** webOS app ID for Luna launch; undefined if no dedicated webOS app is known */
  webosAppId?: string;
}

const enc = encodeURIComponent;

/**
 * Known provider strategies.
 * Tier 1 (search-prefilled): build a search URL for the provider's own app/site.
 * Tier 2 (JustWatch fallback): provider not listed here — fall back to the JustWatch link.
 *
 * Provider IDs from TMDB watch/providers:
 *   8   Netflix           search-prefilled  webOS: netflix
 *   119 Amazon Prime      search-prefilled  webOS: amazon
 *   337 Disney+           search-prefilled  webOS: com.disney.disneyplus-prod
 *   350 Apple TV+         search-prefilled  webOS: com.apple.appletv
 *   192 YouTube           search-prefilled  webOS: youtube.leanback.v4
 *   531 Paramount+        search-prefilled  (no known webOS app ID)
 *   227 Rai Play          search-prefilled  (no known webOS app ID)
 *    39 NOW               search-prefilled  (no known webOS app ID)
 *    11 MUBI              search-prefilled  (no known webOS app ID)
 */
const PROVIDER_CONFIGS: Record<number, ProviderConfig> = {
  8: { buildUrl: (t) => `https://www.netflix.com/search?q=${enc(t)}`, webosAppId: 'netflix' },
  119: { buildUrl: (t) => `https://www.amazon.it/s?k=${enc(t)}`, webosAppId: 'amazon' },
  337: { buildUrl: (t) => `https://www.disneyplus.com/search/${enc(t)}`, webosAppId: 'com.disney.disneyplus-prod' },
  350: { buildUrl: (t) => `https://tv.apple.com/search?term=${enc(t)}`, webosAppId: 'com.apple.appletv' },
  192: { buildUrl: (t) => `https://www.youtube.com/results?search_query=${enc(t)}`, webosAppId: 'youtube.leanback.v4' },
  531: { buildUrl: (t) => `https://www.paramountplus.com/search/${enc(t)}/` },
  227: { buildUrl: (t) => `https://www.raiplay.it/ricerca?q=${enc(t)}` },
  39: { buildUrl: (t) => `https://www.nowtv.it/cerca#${enc(t)}` },
  11: { buildUrl: (t) => `https://mubi.com/it/search?q=${enc(t)}` },
};

@Injectable({ providedIn: 'root' })
export class ProviderDeepLinkService {
  /**
   * Build a launch payload for the given provider.
   *
   * Strategy:
   *  1. If the provider is in PROVIDER_CONFIGS → search-prefilled URL + optional webOS app ID.
   *  2. Otherwise → fall back to the JustWatch link TMDB provides (justWatchLink).
   */
  build(providerId: number, title: string, justWatchLink?: string): ProviderLaunchPayload {
    const config = PROVIDER_CONFIGS[providerId];
    if (config) {
      return { url: config.buildUrl(title), webosAppId: config.webosAppId };
    }
    return { url: justWatchLink ?? '' };
  }
}

import { Injectable } from '@angular/core';
import { SEEN_TITLES_KEY } from './selection.models';

@Injectable({ providedIn: 'root' })
export class SeenTitlesService {
  private _seen = new Set<number>(this._load());

  private _load(): number[] {
    try {
      const raw = localStorage.getItem(SEEN_TITLES_KEY);
      const parsed: unknown = raw ? JSON.parse(raw) : [];
      return Array.isArray(parsed) ? (parsed as number[]) : [];
    } catch {
      return [];
    }
  }

  private _persist(): void {
    try {
      localStorage.setItem(SEEN_TITLES_KEY, JSON.stringify([...this._seen]));
    } catch {
      // localStorage may be unavailable (e.g., private mode with storage full)
    }
  }

  has(id: number): boolean {
    return this._seen.has(id);
  }

  markSeen(id: number): void {
    this._seen.add(id);
    this._persist();
  }

  clear(): void {
    this._seen.clear();
    try {
      localStorage.removeItem(SEEN_TITLES_KEY);
    } catch {
      // ignore
    }
  }

  get size(): number {
    return this._seen.size;
  }

  getAll(): number[] {
    return [...this._seen];
  }
}

import { Injectable, OnDestroy, inject, signal } from '@angular/core';
import { Subscription } from 'rxjs';
import { filter } from 'rxjs/operators';
import { InputDispatcherService } from '../input/input-dispatcher.service';

const FOCUSABLE_SELECTOR = [
  'a[href]',
  'button:not([disabled])',
  'input:not([disabled])',
  'select:not([disabled])',
  'textarea:not([disabled])',
  '[tabindex]:not([tabindex="-1"])',
  '[role="button"]:not([aria-disabled="true"])',
].join(',');

@Injectable({ providedIn: 'root' })
export class SpatialNavigationService implements OnDestroy {
  private readonly dispatcher = inject(InputDispatcherService);
  private _subscription: Subscription | null = null;

  readonly enabled = signal(false);

  enable(): void {
    if (this.enabled()) return;
    this.enabled.set(true);
    this._subscription = this.dispatcher.events$
      .pipe(filter(() => this.enabled()))
      .subscribe((evt) => this._handle(evt.action, evt.originalEvent));
  }

  disable(): void {
    this.enabled.set(false);
    this._subscription?.unsubscribe();
    this._subscription = null;
  }

  ngOnDestroy(): void {
    this.disable();
  }

  private _handle(action: string, originalEvent: Event): void {
    switch (action) {
      case 'navigate-up':
        this._moveFocus('up', originalEvent);
        break;
      case 'navigate-down':
        this._moveFocus('down', originalEvent);
        break;
      case 'navigate-left':
        this._moveFocus('left', originalEvent);
        break;
      case 'navigate-right':
        this._moveFocus('right', originalEvent);
        break;
      case 'confirm':
        this._confirmFocused(originalEvent);
        break;
    }
  }

  private _getFocusableElements(): HTMLElement[] {
    return Array.from(document.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR)).filter(
      (el) => !el.closest('[aria-hidden="true"]') && this._isVisible(el),
    );
  }

  private _isVisible(el: HTMLElement): boolean {
    const rect = el.getBoundingClientRect();
    return rect.width > 0 || rect.height > 0 || el.getClientRects().length > 0;
  }

  private _moveFocus(direction: 'up' | 'down' | 'left' | 'right', originalEvent: Event): void {
    const focusable = this._getFocusableElements();
    const current = document.activeElement as HTMLElement | null;
    if (!focusable.length) return;

    if (!current || !focusable.includes(current)) {
      focusable[0].focus();
      originalEvent.preventDefault();
      return;
    }

    const currentRect = current.getBoundingClientRect();
    const candidates = focusable.filter((el) => {
      if (el === current) return false;
      const r = el.getBoundingClientRect();
      switch (direction) {
        case 'up': return r.bottom <= currentRect.top + 1;
        case 'down': return r.top >= currentRect.bottom - 1;
        case 'left': return r.right <= currentRect.left + 1;
        case 'right': return r.left >= currentRect.right - 1;
      }
    });

    if (!candidates.length) return;

    const best = candidates.reduce((a, b) => {
      return this._distance(a.getBoundingClientRect(), currentRect) <=
        this._distance(b.getBoundingClientRect(), currentRect)
        ? a
        : b;
    });

    best.focus();
    originalEvent.preventDefault();
  }

  private _distance(r: DOMRect, from: DOMRect): number {
    const cx = from.left + from.width / 2;
    const cy = from.top + from.height / 2;
    const tx = r.left + r.width / 2;
    const ty = r.top + r.height / 2;
    return Math.hypot(tx - cx, ty - cy);
  }

  private _confirmFocused(originalEvent: Event): void {
    const active = document.activeElement as HTMLElement | null;
    if (!active) return;
    const tag = active.tagName.toLowerCase();
    if (tag === 'button' || tag === 'a' || active.getAttribute('role') === 'button') {
      active.click();
      originalEvent.preventDefault();
    }
  }
}

import { HttpClient, HttpErrorResponse, HttpParams } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable, throwError } from 'rxjs';
import { catchError, retry, shareReplay } from 'rxjs/operators';
import {
  TmdbDiscoverParams,
  TmdbDiscoverResponse,
  TmdbGenresResponse,
  TmdbMovie,
  TmdbMovieDetail,
  TmdbSearchParams,
  TmdbTvDetail,
  TmdbTvShow,
  TmdbWatchProvidersResponse,
} from './tmdb.models';
import { TmdbConfigService } from './tmdb-config.service';

const RETRY_COUNT = 2;
const CACHE_SIZE = 1;

@Injectable({ providedIn: 'root' })
export class TmdbClient {
  private readonly http = inject(HttpClient);
  private readonly config = inject(TmdbConfigService);

  private readonly genresMovie$ = this.fetchGenres('movie');
  private readonly genresTv$ = this.fetchGenres('tv');
  private readonly watchProviders$ = this.fetchWatchProviders();

  private get authHeaders(): Record<string, string> {
    return { Authorization: `Bearer ${this.config.token}` };
  }

  private handleError(err: HttpErrorResponse): Observable<never> {
    const message =
      err.error?.status_message ?? `HTTP ${err.status}: ${err.statusText}`;
    return throwError(() => new Error(message));
  }

  private fetchGenres(mediaType: 'movie' | 'tv'): Observable<TmdbGenresResponse> {
    return this.http
      .get<TmdbGenresResponse>(`${this.config.baseUrl}/genre/${mediaType}/list`, {
        headers: this.authHeaders,
        params: new HttpParams().set('language', 'en-US'),
      })
      .pipe(
        retry(RETRY_COUNT),
        catchError((e) => this.handleError(e)),
        shareReplay(CACHE_SIZE),
      );
  }

  private fetchWatchProviders(): Observable<TmdbWatchProvidersResponse> {
    return this.http
      .get<TmdbWatchProvidersResponse>(`${this.config.baseUrl}/watch/providers/movie`, {
        headers: this.authHeaders,
        params: new HttpParams()
          .set('language', 'en-US')
          .set('watch_region', this.config.region),
      })
      .pipe(
        retry(RETRY_COUNT),
        catchError((e) => this.handleError(e)),
        shareReplay(CACHE_SIZE),
      );
  }

  getMovieGenres(): Observable<TmdbGenresResponse> {
    return this.genresMovie$;
  }

  getTvGenres(): Observable<TmdbGenresResponse> {
    return this.genresTv$;
  }

  getWatchProviders(): Observable<TmdbWatchProvidersResponse> {
    return this.watchProviders$;
  }

  discover(params: TmdbDiscoverParams): Observable<TmdbDiscoverResponse<TmdbMovie | TmdbTvShow>> {
    const { mediaType, page = 1, withGenres, withWatchProviders, watchRegion, voteAverageGte, sortBy } = params;
    let httpParams = new HttpParams()
      .set('language', 'en-US')
      .set('page', page.toString())
      .set('sort_by', sortBy ?? 'popularity.desc');

    if (withGenres?.length) {
      httpParams = httpParams.set('with_genres', withGenres.join('|'));
    }
    if (withWatchProviders?.length) {
      httpParams = httpParams.set('with_watch_providers', withWatchProviders.join('|'));
    }
    if (watchRegion ?? this.config.region) {
      httpParams = httpParams.set('watch_region', watchRegion ?? this.config.region);
    }
    if (voteAverageGte !== undefined) {
      httpParams = httpParams.set('vote_average.gte', voteAverageGte.toString());
    }

    return this.http
      .get<TmdbDiscoverResponse<TmdbMovie | TmdbTvShow>>(
        `${this.config.baseUrl}/discover/${mediaType}`,
        { headers: this.authHeaders, params: httpParams },
      )
      .pipe(
        retry(RETRY_COUNT),
        catchError((e) => this.handleError(e)),
      );
  }

  getMovieDetail(id: number): Observable<TmdbMovieDetail> {
    return this.http
      .get<TmdbMovieDetail>(`${this.config.baseUrl}/movie/${id}`, {
        headers: this.authHeaders,
        params: new HttpParams()
          .set('language', 'en-US')
          .set('append_to_response', 'credits,videos,watch/providers')
          .set('watch_region', this.config.region),
      })
      .pipe(
        retry(RETRY_COUNT),
        catchError((e) => this.handleError(e)),
      );
  }

  getTvDetail(id: number): Observable<TmdbTvDetail> {
    return this.http
      .get<TmdbTvDetail>(`${this.config.baseUrl}/tv/${id}`, {
        headers: this.authHeaders,
        params: new HttpParams()
          .set('language', 'en-US')
          .set('append_to_response', 'credits,videos,watch/providers')
          .set('watch_region', this.config.region),
      })
      .pipe(
        retry(RETRY_COUNT),
        catchError((e) => this.handleError(e)),
      );
  }

  search(params: TmdbSearchParams): Observable<TmdbDiscoverResponse<TmdbMovie | TmdbTvShow>> {
    const { mediaType, query, page = 1 } = params;
    const httpParams = new HttpParams()
      .set('query', query)
      .set('language', 'en-US')
      .set('page', page.toString());

    return this.http
      .get<TmdbDiscoverResponse<TmdbMovie | TmdbTvShow>>(
        `${this.config.baseUrl}/search/${mediaType}`,
        { headers: this.authHeaders, params: httpParams },
      )
      .pipe(
        retry(RETRY_COUNT),
        catchError((e) => this.handleError(e)),
      );
  }
}

import { Injectable, inject } from '@angular/core';
import { ENVIRONMENT } from '../../shared/environment.token';
import { detectRegion } from './detect-region';

@Injectable({ providedIn: 'root' })
export class TmdbConfigService {
  private readonly env = inject(ENVIRONMENT);

  readonly baseUrl = 'https://api.themoviedb.org/3' as const;
  readonly imageBaseUrl = 'https://image.tmdb.org/t/p' as const;

  get token(): string {
    return this.env.tmdbToken;
  }

  get region(): string {
    return this.env.tmdbRegion || detectRegion();
  }

  imageUrl(path: string, size = 'w342'): string {
    return `${this.imageBaseUrl}/${size}${path}`;
  }
}

import { Injectable } from '@angular/core';
import { LunaBridge, LunaLaunchOptions } from './platform.model';

/** Web stub for LunaBridge — no-ops since Luna is only available on webOS. */
@Injectable({ providedIn: 'root' })
export class WebLunaBridge implements LunaBridge {
  isAvailable(): boolean {
    return false;
  }

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  launchApp(_options: LunaLaunchOptions): Promise<void> {
    return Promise.resolve();
  }
}

import { Injectable } from '@angular/core';
import { LunaBridge, LunaLaunchOptions } from './platform.model';

declare global {
  interface Window {
    webOS?: {
      service: {
        request: (
          uri: string,
          options: {
            method: string;
            parameters?: Record<string, unknown>;
            onSuccess?: (response: unknown) => void;
            onFailure?: (error: unknown) => void;
          },
        ) => void;
      };
    };
  }
}

/** Real webOS Luna bridge — calls the platform's app-manager service to launch provider apps. */
@Injectable()
export class WebOSLunaBridge implements LunaBridge {
  isAvailable(): boolean {
    return typeof window.webOS !== 'undefined' && !!window.webOS.service;
  }

  launchApp(options: LunaLaunchOptions): Promise<void> {
    return new Promise((resolve, reject) => {
      window.webOS!.service.request('luna://com.webos.service.applicationmanager', {
        method: 'launch',
        parameters: { id: options.appId, params: options.params ?? {} },
        onSuccess: () => resolve(),
        onFailure: (err) => reject(err),
      });
    });
  }
}

import { Injectable, inject } from '@angular/core';
import { LunaBridge, ProviderLaunchPayload, ProviderLauncher } from './platform.model';
import { LUNA_BRIDGE } from './platform.tokens';

/** Unified provider launcher — opens the provider URL on web or launches the app on webOS. */
@Injectable({ providedIn: 'root' })
export class WebProviderLauncherService implements ProviderLauncher {
  private readonly luna: LunaBridge = inject(LUNA_BRIDGE);

  launch(payload: ProviderLaunchPayload): void {
    if (this.luna.isAvailable()) {
      if (payload.webosAppId) {
        void this.luna.launchApp({ appId: payload.webosAppId });
      }
      return;
    }
    window.open(payload.url, '_blank', 'noopener,noreferrer');
  }
}

