export class FiltersComponent {
  protected readonly store = inject(CriteriaStore);
  private readonly router = inject(Router);
  private readonly tmdb = inject(TmdbClient);

  private readonly movieGenres = toSignal(
    this.tmdb.getMovieGenres().pipe(map((r) => r.genres)),
    { initialValue: [] },
  );
  private readonly tvGenres = toSignal(
    this.tmdb.getTvGenres().pipe(map((r) => r.genres)),
    { initialValue: [] },
  );
  protected readonly watchProviders = toSignal(
    this.tmdb.getWatchProviders().pipe(map((r) => r.results)),
    { initialValue: [] },
  );

  protected readonly genres = computed(() =>
    this.store.mediaType() === 'movie' ? this.movieGenres() : this.tvGenres(),
  );

  protected pick(): void {
    void this.router.navigate(['/pick']);
  }
}

