import { SlicePipe } from '@angular/common';
import { Component, OnInit, computed, inject } from '@angular/core';
import { RouterLink } from '@angular/router';
import { PosterComponent } from '../../design-system/components/poster/poster.component';
import { RatingComponent } from '../../design-system/components/rating/rating.component';
import { ButtonComponent } from '../../design-system/primitives/button/button.component';
import { SpinnerComponent } from '../../design-system/primitives/spinner/spinner.component';
import { DiscoverSelectionService } from '../../core/selection/discover-selection.service';
import { SeenTitlesService } from '../../core/selection/seen-titles.service';
import { SpatialNavZoneDirective } from '../../core/spatial-navigation/spatial-nav-zone.directive';
import { TmdbConfigService } from '../../core/tmdb/tmdb-config.service';
import { CriteriaStore } from '../criteria/criteria.store';

@Component({
  selector: 'app-pick',
  imports: [RouterLink, SlicePipe, ButtonComponent, SpinnerComponent, PosterComponent, RatingComponent, SpatialNavZoneDirective],
  template: `
    <main class="pick-screen" appSpatialNavZone>
      @switch (service.state().status) {
        @case ('loading') {
          <div class="pick-screen__loading" aria-live="polite" aria-busy="true">
            <ds-spinner size="lg" />
            <h1 class="pick-screen__loading-text">Finding your next watch…</h1>
          </div>
        }

        @case ('picked') {
          @if (pickedItem(); as item) {
            <article class="pick-screen__result" aria-label="Picked title">
              <div class="pick-screen__poster">
                @if (posterUrl(item.posterPath); as url) {
                  <ds-poster [src]="url" [alt]="item.title" />
                }
              </div>
              <div class="pick-screen__info">
                <h1 class="pick-screen__title">{{ item.title }}</h1>
                <div class="pick-screen__meta">
                  <ds-rating [value]="item.voteAverage" />
                  <span class="pick-screen__year">{{ item.releaseDate | slice: 0 : 4 }}</span>
                </div>
                <p class="pick-screen__overview">{{ item.overview }}</p>
                <div class="pick-screen__actions">
                  <ds-button variant="primary" [routerLink]="['/detail', item.mediaType, item.id]">See details</ds-button>
                  <ds-button variant="ghost" (click)="showAnother()">Already seen? Show another</ds-button>
                  <ds-button variant="secondary" routerLink="/">Back to filters</ds-button>
                </div>
              </div>
            </article>
          }
        }

        @case ('empty') {
          <div class="pick-screen__state" aria-live="polite">
            <h1 class="pick-screen__state-heading">No results</h1>
            <p class="pick-screen__state-message">No titles found for your filters.</p>
            <ds-button variant="primary" routerLink="/">Change filters</ds-button>
          </div>
        }

        @case ('exhausted') {
          <div class="pick-screen__state" aria-live="polite">
            <h1 class="pick-screen__state-heading">All caught up!</h1>
            <p class="pick-screen__state-message">
              You've seen everything in this category!
            </p>
            <div class="pick-screen__actions">
              <ds-button variant="primary" (click)="resetAndPick()">Pick again from the start</ds-button>
              <ds-button variant="secondary" routerLink="/">Back to filters</ds-button>
            </div>
          </div>
        }

        @case ('error') {
          <div class="pick-screen__state" aria-live="polite" role="alert">
            <h1 class="pick-screen__state-heading">Something went wrong</h1>
            <p class="pick-screen__state-message">
              {{ errorMessage() }}
            </p>
            <div class="pick-screen__actions">
              <ds-button variant="primary" (click)="retry()">Try again</ds-button>
              <ds-button variant="secondary" routerLink="/">Back to filters</ds-button>
            </div>
          </div>
        }

        @default {
          <!-- idle: pick is called in ngOnInit, this state is transitional -->
        }
      }
    </main>
  `,
  styles: [
    `
      .pick-screen {
        max-width: 900px;
        margin: 0 auto;
        padding: var(--space-6) var(--space-4);
        min-height: 60vh;
        display: flex;
        align-items: flex-start;
      }

      .pick-screen__loading {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: var(--space-4);
        width: 100%;
        padding-top: var(--space-16);
      }

      .pick-screen__loading-text {
        margin: 0;
        color: var(--color-text-secondary);
        font-size: var(--font-size-lg);
        font-weight: 400;
      }

      .pick-screen__state-heading {
        margin: 0;
        font-size: var(--font-size-2xl);
        font-weight: 700;
      }

      .pick-screen__result {
        display: grid;
        grid-template-columns: 220px 1fr;
        gap: var(--space-6);
        width: 100%;
      }

      .pick-screen__poster {
        width: 220px;
      }

      .pick-screen__title {
        font-size: var(--font-size-3xl);
        font-weight: 700;
        margin: 0 0 var(--space-3);
      }

      .pick-screen__meta {
        display: flex;
        align-items: center;
        gap: var(--space-4);
        margin-bottom: var(--space-4);
      }

      .pick-screen__year {
        font-size: var(--font-size-sm);
        color: var(--color-text-secondary);
      }

      .pick-screen__overview {
        color: var(--color-text-secondary);
        line-height: 1.6;
        margin-bottom: var(--space-6);
      }

      .pick-screen__actions {
        display: flex;
        gap: var(--space-3);
        flex-wrap: wrap;
      }

      .pick-screen__state {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: var(--space-4);
        padding-top: var(--space-16);
        width: 100%;
        text-align: center;
      }

      .pick-screen__state-message {
        font-size: var(--font-size-lg);
        color: var(--color-text-secondary);
        max-width: 400px;
      }
    `,
  ],
})
export class PickComponent implements OnInit {
  protected readonly service = inject(DiscoverSelectionService);
  private readonly store = inject(CriteriaStore);
  private readonly seen = inject(SeenTitlesService);
  private readonly config = inject(TmdbConfigService);

  protected readonly pickedItem = computed(() => {
    const s = this.service.state();
    return s.status === 'picked' ? s.item : null;
  });

  protected readonly errorMessage = computed(() => {
    const s = this.service.state();
    return s.status === 'error' ? s.message : null;
  });

  ngOnInit(): void {
    this.service.pick(this.store.selectionCriteria());
  }

  protected showAnother(): void {
    this.service.pickAnother();
  }

  protected resetAndPick(): void {
    this.seen.clear();
    this.service.pick(this.store.selectionCriteria());
  }

  protected retry(): void {
    this.service.pick(this.store.selectionCriteria());
  }

  protected posterUrl(path: string | null): string | null {
    return path ? this.config.imageUrl(path, 'w342') : null;
  }
}

